function flag(iso3){
  try{
    const i2=ISO2[iso3];if(!i2)return '';
    const emoji=String.fromCodePoint(...[...i2].map(c=>0x1F1E6+c.charCodeAt(0)-65));
    return '<span style="display:inline-block;width:1.6em;height:1.2em;vertical-align:middle;margin-right:.4em;flex-shrink:0;font-style:normal;font-size:1.15em">'+emoji+'</span>';
  }catch(e){return '';}
}
// Run twemoji on the tooltip whenever it updates
function applyTwemoji(el){
  if(window.twemoji && el) twemoji.parse(el,{folder:'svg',ext:'.svg'});
}


