function nWGI(x){return Math.max(0,Math.min(100,(x+2.5)/5*100))}
function nGTI(g){return Math.max(0,Math.min(100,100-g*10))}
function nINF(iso3){
  const raw=INF_RAW[iso3],exp=GDP_BRACKET[iso3];
  if(raw===undefined||exp===undefined) return undefined;
  return Math.max(0,Math.min(100,50+(raw-exp)*25));
}
function nHOM(r){return Math.max(0,100*(1-Math.log(1+r)/Math.log(72)))}
function nSE(s){return Math.max(0,Math.min(100,100*(1-Math.max(0,s-5)/60)))}
function nRTR(r){return Math.max(0,100*(1-Math.log(1+r)/Math.log(42)))}

function calcScore(iso3){
  const w=WGI[iso3]; if(!w) return null;
  const avail={},d={name:w.n};
  d.cc=w.cc; avail.cc=nWGI(w.cc);
  const ge=GE[iso3]; if(ge!==undefined){d.ge=ge;avail.ge=nWGI(ge);}
  const se=SE[iso3]; if(se!==undefined){d.se=se;avail.se=nSE(se);}
  const wvs=WVS[iso3]; if(wvs!==undefined){d.wvs=wvs;avail.wvs=wvs;}
  const lsc=LSC[iso3]; if(lsc!=null){d.lsc=lsc;avail.lsc=lsc;}
  const glo=GLO[iso3]; if(glo!==undefined){d.glo=glo;avail.glo=glo;}
  const wlt=WLT[iso3]; if(wlt!==undefined){d.wlt=wlt;avail.wlt=wlt;}
  const gcbR=GCB_RAW[iso3]; if(gcbR!==undefined){d.gcbR=gcbR;avail.gcb=100-gcbR;}
  const hom=HOM[iso3]; if(hom!==undefined){d.hom=hom;avail.hom=nHOM(hom);}
  const rtr=RTR[iso3]; if(rtr!==undefined){d.rtr=rtr;avail.rtr=nRTR(rtr);}
  const epi=EPI[iso3]; if(epi!==undefined){d.epi=epi;avail.epi=epi;}
  const gtiR=GTI[iso3]; if(gtiR!==undefined){d.gtiR=gtiR;avail.gti=nGTI(gtiR);}
  const infR=INF_RAW[iso3]; const infN=nINF(iso3); if(infN!==undefined){d.infR=infR;d.infN=infN;avail.inf=infN;}
  const totalW=Object.keys(avail).reduce((s,k)=>s+WEIGHTS[k],0);
  d.score=Object.entries(avail).reduce((s,[k,v])=>s+(v*WEIGHTS[k]/totalW),0);
  d.nComp=Object.keys(avail).length;
  d._n=avail;
  d.iso3=iso3;
  d._avail=avail;
  return d;
}

const byNum={},byISO={};
for(const iso3 of Object.keys(WGI)){
  const num=I3N[iso3]; if(!num) continue;
  const r=calcScore(iso3); if(!r) continue;
  byNum[num]=r; byISO[iso3]=r;
}
const vals=Object.values(byNum);
const n9p=vals.filter(d=>d.nComp>=9).length;
const n68=vals.filter(d=>d.nComp>=6&&d.nComp<9).length;
document.getElementById('status').textContent=
  `${vals.length} countries scored across 13 components`;
const _hdn=document.getElementById('hd-n');if(_hdn)_hdn.textContent=vals.length;

// Score stretching: observed range ~27.8 to ~90.3, stretched to use full red→blue gradient
const SCORE_MIN=27,SCORE_MAX=91;
function tc(v){
  // Stretch v from [SCORE_MIN..SCORE_MAX] to [0..1]
  let t=(v-SCORE_MIN)/(SCORE_MAX-SCORE_MIN);
  t=Math.max(0,Math.min(1,t));
  // Mid-point at 0.5 = amber pivot
  return t<.5
    ?d3.interpolateRgb('#9a2010','#c87830')(t*2)
    :d3.interpolateRgb('#c87830','#4a90e8')((t-.5)*2);
}
function sColor(n){return n>=9?'rgba(255,255,255,.09)':n>=6?'rgba(255,255,255,.05)':'rgba(255,255,255,.025)'}

const lc=document.getElementById('lgd').getContext('2d');
for(let i=0;i<400;i++){lc.fillStyle=tc(i/400*100);lc.fillRect(i,0,1,10);}

