let summaryTimer=null;
function showSummary(iso3){
  const el=document.getElementById('tsummary');
  el.classList.remove('loading');
  if(iso3 && DESC[iso3]){
    el.textContent=DESC[iso3];
  } else {
    el.textContent='';
  }
}


function showTip(ev,r,name,_numKey){
  // Resolve territory info if no data
  const numKey=_numKey||'';
  const terr=TERRITORY[numKey];
  if(!r && terr) name=terr.name;
  if(!r && !terr && (!name||name==='Unknown')) name='Unnamed territory';
  let flagEmoji='';
  if(r?.iso3){
    flagEmoji=flag(r.iso3);
  } else {
    // Try territory name lookup
    const terrName=(terr&&terr.name)||name||'';
    if(TERR_FLAG[terrName]){
      const i2=TERR_FLAG[terrName].toLowerCase();
      flagEmoji='<span style="display:inline-block;width:1.3em;height:1em;vertical-align:middle;margin-right:.35em;font-style:normal">'+String.fromCodePoint(...[...TERR_FLAG[terrName]].map(c=>0x1F1E6+c.charCodeAt(0)-65))+'</span>';
    } else if(numKey && N2I[numKey]){
      flagEmoji=flag(N2I[numKey]);
    }
  }
  const tnEl=document.getElementById('tn');
  tnEl.innerHTML=flagEmoji+'<span style="font-style:italic">'+(name||'—')+'</span>';
  applyTwemoji(tnEl);
  if(r){
    const filtScore=recalcScoreFiltered(r);
    const dispScore=filtScore!==null?filtScore:r.score;
    document.getElementById('tsc').innerHTML=`<strong>${dispScore.toFixed(1)}</strong> / 100 &nbsp;·&nbsp; CTI score`;
    // Look up pre-generated description by ISO3
    showSummary(r.iso3);
    const f=(lbl,raw,norm,u,wt,src)=>
      `<div class="tr"><span>${lbl} <span style="color:var(--faint)">${wt}%</span></span><span>${typeof raw==='number'?Number(raw).toFixed(raw<10?2:1):raw}${u} → ${Number(norm).toFixed(0)}</span></div>`;
    const m=(lbl,wt,src)=>`<div class="tr miss"><span>${lbl} <span style="color:var(--faint)">${wt}%</span></span><span>no data</span></div>`;
    const sep=`<div class="tsep"></div>`;
    let rows='';
    rows+='<div class="tgrp-lbl">Institutional</div>';
    rows+=f('Corruption Control',r.cc,r._n.cc,'',3,'WB WGI 2023');
    rows+=(r.ge!==undefined)?f('Government Effectiveness',r.ge,r._n.ge,'',3,'WB WGI 2023'):m('Government Effectiveness',3,'WB WGI 2023');
    rows+=sep;
    rows+='<div class="tgrp-lbl">Fiscal Compliance</div>';
    rows+=(r.se!==undefined)?f('Shadow Economy',r.se+'%',r._n.se,'',6,'Schneider ~2018'):m('Shadow Economy',6,'Schneider ~2018');
    rows+=sep;
    rows+='<div class="tgrp-lbl">Attitudinal Trust</div>';
    rows+=(r.wvs!==undefined)?f('Interpersonal Trust',r.wvs+'%',r.wvs,'',8,'WVS 2017–22'):m('Interpersonal Trust',8,'WVS 2017–22');
    rows+=(r.lsc!==undefined)?f('Social Capital',r.lsc.toFixed(1),r.lsc,'',8,'Legatum 2023'):m('Social Capital',8,'Legatum 2023');
    rows+=sep;
    rows+='<div class="tgrp-lbl">Safety &amp; Order</div>';
    rows+=(r.glo!==undefined)?f('Law & Order',r.glo,r.glo,'',12,'Gallup 2023'):m('Law & Order',12,'Gallup 2023');
    rows+=sep;
    rows+='<div class="tgrp-lbl">Civic Honesty</div>';
    rows+=(r.wlt!==undefined)?f('Wallet Return Rate',r.wlt+'%',r.wlt,'',12,'Cohn 2019'):m('Wallet Return Rate',12,'Cohn 2019');
    rows+=(r.gcbR!==undefined)?f('Bribery-Free Rate',r.gcbR+'% paid',100-r.gcbR,'',10,'TI GCB 2017'):m('Bribery-Free Rate',10,'TI GCB 2017');
    rows+=sep;
    rows+='<div class="tgrp-lbl">Outcomes</div>';
    rows+=(r.hom!==undefined)?f('Homicide Rate',r.hom,r._n.hom,'/100k',7,'UNODC 2021–23'):m('Homicide Rate',7,'UNODC 2021–23');
    rows+=(r.rtr!==undefined)?f('Road Deaths',r.rtr,r._n.rtr,'/100k',6,'WHO 2021'):m('Road Deaths',6,'WHO 2021');
    rows+=(r.epi!==undefined)?f('Waste Management',r.epi,r.epi,'',6,'Yale EPI 2022'):m('Waste Management',6,'Yale EPI 2022');
    rows+=(r.gtiR!==undefined)?f('Terrorism Index',r.gtiR,nGTI(r.gtiR),'',8,'IEP GTI 2023'):m('Terrorism Index',8,'IEP GTI 2023');
    rows+=sep;
    rows+='<div class="tgrp-lbl">Public Goods</div>';
    rows+=(r.infN!==undefined)?f('Infrastructure',r.infR.toFixed(1),r.infN,'/5',11,'WB LPI 2023'):m('Infrastructure',11,'WB LPI 2023');
    document.getElementById('trows').innerHTML=rows;
    document.getElementById('tfoot').textContent=`${r.nComp} of 13 components · proportionally weighted`;
  }else{
    const terrInfo=TERRITORY[numKey||''];
    document.getElementById('tsc').innerHTML='<span style="color:var(--muted)">No index data available</span>';
    const summEl=document.getElementById('tsummary');
    summEl.classList.remove('loading');
    if(terrInfo){
      summEl.textContent=terrInfo.info;
    } else if(name&&name!=='Unknown'&&name!=='Unnamed territory'){
      summEl.textContent='No governance or social trust data available for this territory in the source datasets.';
    } else {
      summEl.textContent='';
    }
    clearTimeout(summaryTimer);
    document.getElementById('trows').innerHTML='';
    document.getElementById('tfoot').textContent='';
  }
  // Fixed viewport positioning — floats above everything
  const tw=270,th=420,pad=10;
  let tx=ev.clientX+16, ty=ev.clientY+14;
  if(tx+tw>window.innerWidth-pad) tx=ev.clientX-tw-10;
  if(ty+th>window.innerHeight-pad) ty=ev.clientY-th-10;
  tx=Math.max(pad,tx); ty=Math.max(pad,ty);
  tip.style.left=tx+'px';tip.style.top=ty+'px';tip.style.opacity='1';
}




